};

function getReadableName(type, displayName) {
  return typeMap[type] || displayName || type;
}

// ─── Walk connections to build ordered sequence ───────────────────────────────
const nodes = workflow.nodes;
const connections = workflow.connections || {};

// Build a lookup: node name → node object
const nodeByName = {};
for (const node of nodes) {
  nodeByName[node.name] = node;
}

// Find all nodes that are pointed TO (they have incoming connections)
const hasIncoming = new Set();
for (const [, outputs] of Object.entries(connections)) {
  for (const portGroup of Object.values(outputs)) {
    for (const targets of portGroup) {
      for (const target of targets) {
        hasIncoming.add(target.node);
      }
    }
  }
}

// Root nodes = nodes with NO incoming connections (triggers)
const roots = nodes.filter(n => !hasIncoming.has(n.name));

// BFS walk from each root to build the sequence
const visited = new Set();
const sequence = [];

function walk(nodeName) {
  if (visited.has(nodeName)) return;
  visited.add(nodeName);

  const node = nodeByName[nodeName];
  if (!node) return;

  // Skip sticky notes
  if (node.type === "n8n-nodes-base.stickyNote") return;

  sequence.push({
    name: node.name,
    readable: getReadableName(node.type, node.name),
    type: node.type,
  });

  // Follow connections
  const outgoing = connections[nodeName];
  if (!outgoing) return;

  for (const portGroup of Object.values(outgoing)) {
    for (const targets of portGroup) {
      for (const target of targets) {
        walk(target.node);
      }
    }
  }
}

for (const root of roots) {
  walk(root.name);
}

// ─── Build readable text output ───────────────────────────────────────────────
const sequenceText = sequence
  .map((n, i) => `  Step ${i + 1}: ${n.readable} ("${n.name}")`)
  .join("\n");

const flowArrow = sequence.map(n => n.readable).join(" → ");

const summary = `Workflow: "${workflow.name}"
Total Nodes: ${nodes.filter(n => n.type !== "n8n-nodes-base.stickyNote").length}

Logical Sequence:
${sequenceText}

Flow Overview:
  ${flowArrow}`;

return { json: { summary } };

