// Get all files from Google Drive
const driveFiles = $('Search files and folders').all().map(i => i.json);

// Get all rows from Google Sheet
const sheetRows = $('Get row(s) in sheet').all().map(i => i.json);

// Get all names already in the sheet
const sheetNames = sheetRows.map(r => r.Name);

// Filter: only return Drive files NOT yet in the sheet
const newFiles = driveFiles.filter(f => !sheetNames.includes(f.name));

// If nothing new, return empty
if (newFiles.length === 0) {
  return [{ json: { message: "No new files to process" } }];
}

return newFiles.map(f => ({ json: f }));
